<style>
.admin-shell{padding:24px 28px 36px}.admin-hero,.admin-card{background:rgba(255,255,255,.9);border:1px solid rgba(58,110,165,.14);border-radius:20px;padding:24px;box-shadow:0 18px 46px rgba(30,72,126,.10)}.admin-hero{margin-bottom:18px}.admin-kicker{font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.08em;color:#1BA784}.admin-hero h1,.admin-card h1,.admin-card h2{margin:4px 0;color:#1C2B3A;font-weight:800}.admin-hero p{color:#416C92;margin:4px 0 0}.admin-grid{display:grid;grid-template-columns:minmax(280px,380px) 1fr;gap:18px}.admin-card.wide{max-width:760px}.admin-card label{display:block;font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.07em;color:#416C92;margin:14px 0 8px}.admin-card input[type=text],.admin-card input[type=password],.admin-card select{width:100%;border:1.5px solid #DDE8F4;border-radius:12px;background:#F7FAFD;color:#1C2B3A;font:14px Inter,sans-serif;padding:11px 13px;outline:none}.admin-card button{border:none;border-radius:12px;background:linear-gradient(135deg,#3A6EA5,#1BA784);color:#fff;font-weight:800;padding:10px 16px;margin-top:14px}.check-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:8px}.check-grid label{margin:0;background:#F7FAFD;border:1px solid #DDE8F4;border-radius:10px;padding:9px;text-transform:none;letter-spacing:0;font-size:13px}.admin-table{width:100%;border-collapse:collapse}.admin-table th,.admin-table td{padding:11px;border-bottom:1px solid #EEF4FA;text-align:left;font-size:13px}.admin-table th{font-size:11px;text-transform:uppercase;color:#416C92}.admin-table a,.admin-table button{display:inline-flex;border:1px solid #DDE8F4;background:#F7FAFD;border-radius:9px;padding:6px 9px;color:#255F8C;text-decoration:none;font-size:12px;font-weight:800;margin-right:4px}.admin-table form{display:inline}.admin-table button{color:#C0392B;margin-top:0}.tag{background:#E8F0FB;color:#3A6EA5;border-radius:999px;padding:2px 7px;font-size:10px;font-weight:800}.back-link{display:inline-flex;gap:6px;align-items:center;margin-bottom:14px;color:#255F8C;text-decoration:none;font-weight:800;font-size:13px}.admin-alert{margin-bottom:16px;padding:12px 14px;border-radius:12px;font-size:13px;font-weight:700}.admin-alert.danger{background:#FFF1F0;color:#C0392B;border:1px solid #FFCDC9}@media(max-width:900px){.admin-grid{grid-template-columns:1fr}}
</style>
